xpath.script:
(function () {
    var toggleBtn = document.querySelector('.navbar-toggle');
    var navLinks = document.getElementById('navLinks');
    var navbar = document.getElementById('mainNavbar');

    if (toggleBtn && navLinks) {
        toggleBtn.addEventListener('click', function () {
            navLinks.classList.toggle('open');
        });
    }

    /* Navbar scroll effect */
    if (navbar) {
        window.addEventListener('scroll', function() {
            if (window.scrollY > 50) {
                navbar.classList.add('scrolled');
            } else {
                navbar.classList.remove('scrolled');
            }
        });
    }

    var currentLanguageCode = "";

    function firstPathSegment(pathname) {
        return ((pathname || '').split('/')[1] || '').toLowerCase();
    }

    function isArabicSegment(segment) {
        return segment === 'ar' || segment.indexOf('ar_') === 0 || segment.indexOf('ar-') === 0;
    }

    function currentLanguageLabel() {
        var html = document.documentElement;
        var body = document.body || {};
        var pageLang = ((html.getAttribute('lang') || body.getAttribute('lang') || currentLanguageCode || '') + '').toLowerCase();
        var pageDir = ((html.getAttribute('dir') || body.getAttribute('dir') || '') + '').toLowerCase();
        var currentPathSegment = firstPathSegment(window.location.pathname);
        if (
            pageLang.indexOf('ar') === 0 ||
            currentLanguageCode.toLowerCase().indexOf('ar') === 0 ||
            pageDir === 'rtl' ||
            isArabicSegment(currentPathSegment)
        ) {
            return 'AR';
        }
        return 'EN';
    }

    function inferLanguageLabel(text, href, urlCode) {
        var value = ((text || '') + ' ' + (href || '') + ' ' + (urlCode || '')).toLowerCase();
        var hrefPathSegment = '';
        try {
            hrefPathSegment = firstPathSegment(new URL(href || '/', window.location.origin).pathname);
        } catch (ignore) {}
        if (
            isArabicSegment(hrefPathSegment) ||
            isArabicSegment(urlCode || '') ||
            value.indexOf('arab') !== -1 ||
            value.indexOf('الع') !== -1 ||
            value.indexOf('lang=ar') !== -1
        ) {
            return 'AR';
        }
        return 'EN';
    }

    function fallbackLanguageHref(label) {
        var path = window.location.pathname || '/';
        var searchHash = (window.location.search || '') + (window.location.hash || '');
        var parts = path.split('/');
        var hasArabicPrefix = isArabicSegment(firstPathSegment(path));
        if (label === 'AR') {
            if (hasArabicPrefix) {
                return path + searchHash;
            }
            if (path.charAt(0) !== '/') {
                path = '/' + path;
            }
            return (path === '/' ? '/ar' : '/ar' + path) + searchHash;
        }
        if (hasArabicPrefix) {
            parts.splice(1, 1);
            path = parts.join('/') || '/';
            if (path.charAt(0) !== '/') {
                path = '/' + path;
            }
        }
        return path + searchHash;
    }

    function websiteLanguageHref(urlCode, redirectHref) {
        var redirectUrl = redirectHref || '/';
        return '/website/lang/' + encodeURIComponent(urlCode) + '?r=' + encodeURIComponent(redirectUrl);
    }

    document.querySelectorAll('.pr-language-link-wrap').forEach(function(languageWrap) {
        var activeLabel = currentLanguageLabel();
        var targetLabel = activeLabel === 'AR' ? 'EN' : 'AR';
        var nativeLanguages = {};

        languageWrap.querySelectorAll('.pr-language-link-native a[href]').forEach(function(item) {
            var itemHref = item.getAttribute('href');
            var itemUrlCode = item.getAttribute('data-url_code');
            var itemLabel = inferLanguageLabel(item.textContent, itemHref, itemUrlCode);
            nativeLanguages[itemLabel] = {
                href: itemHref,
                urlCode: itemUrlCode || (itemLabel === 'AR' ? 'ar' : 'en'),
            };
        });

        var languageLink = languageWrap.querySelector('[data-pr-language-link]');
        var languageLabel = languageWrap.querySelector('.pr-language-link-label');
        if (!languageLink) {
            return;
        }

        var targetLanguage = nativeLanguages[targetLabel] || {
            href: fallbackLanguageHref(targetLabel),
            urlCode: targetLabel === 'AR' ? 'ar' : 'en',
        };
        var targetHref = targetLanguage.href || fallbackLanguageHref(targetLabel);
        languageLink.setAttribute('href', websiteLanguageHref(targetLanguage.urlCode, targetHref));
        languageLink.setAttribute('aria-label', targetLabel === 'AR' ? 'Switch to Arabic' : 'Switch to English');
        languageLink.classList.toggle('is-target-ar', targetLabel === 'AR');
        languageLink.classList.toggle('is-target-en', targetLabel === 'EN');
        if (languageLabel) {
            languageLabel.textContent = targetLabel === 'AR' ? 'العربية' : 'English';
        }
    });

    /* Desktop: Improved dropdown with delay to prevent premature close */
    var navItems = document.querySelectorAll('.nav-item');
    navItems.forEach(function(item) {
        var closeTimeout;
        var dropdown = item.querySelector('.services-dropdown');

        item.addEventListener('mouseenter', function() {
            if (window.innerWidth > 992) {
                clearTimeout(closeTimeout);
                item.classList.add('dropdown-open');
            }
        });

        item.addEventListener('mouseleave', function() {
            if (window.innerWidth > 992) {
                closeTimeout = setTimeout(function() {
                    item.classList.remove('dropdown-open');
                }, 300); /* 300ms delay before closing */
            }
        });

        if (dropdown) {
            dropdown.addEventListener('mouseenter', function() {
                clearTimeout(closeTimeout);
                item.classList.add('dropdown-open');
            });

            dropdown.addEventListener('mouseleave', function() {
                closeTimeout = setTimeout(function() {
                    item.classList.remove('dropdown-open');
                }, 300);
            });
        }
    });

    /* Mobile: toggle services dropdown on tap */
    var servicesItem = document.querySelector('.nav-item > a');
    if (servicesItem) {
        servicesItem.addEventListener('click', function (e) {
            if (window.innerWidth <= 992) {
                e.preventDefault();
                var dd = this.parentElement.querySelector('.services-dropdown');
                if (dd) dd.classList.toggle('mobile-open');
            }
        });
    }

    /* Close mobile menu when clicking outside */
    document.addEventListener('click', function(e) {
        if (window.innerWidth <= 992 && !navbar.contains(e.target)) {
            navLinks.classList.remove('open');
        }
    });
})();
